14	const COMPONENT_BASE_PREMIUM = 25;
15	
16	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: COMPONENT_BASE_PREMIUM,
22	  moonstone: COMPONENT_BASE_PREMIUM,
23	};
24	
25	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
26	const PROCESSING_FEE = 5;
27	
28	function basePremiumFor(item: Item): number {
29	  return BASE_PREMIUM_BY_ITEM[item.kind];
30	}
31	
32	type QuoteResult = { kind: "quote"; premium: number };
33	
34	const BUILDING_BLOCK_BASE_PREMIUM = 60;
35	const BUILDING_BLOCK_SIZE = 3;
36	const COMPONENT_KINDS: ReadonlyArray<Item["kind"]> = ["rune", "moonstone"];
37	
38	function groupByKind(items: Item[]): Item[][] {
39	  const groups = new Map<Item["kind"], Item[]>();
40	  for (const item of items) {
41	    const group = groups.get(item.kind) ?? [];
42	    group.push(item);
43	    groups.set(item.kind, group);
44	  }
45	  return Array.from(groups.values());
46	}
47	
48	function isBuildingBlock(group: Item[]): boolean {
49	  return group.length === BUILDING_BLOCK_SIZE && COMPONENT_KINDS.includes(group[0].kind);
50	}
51	
52	function basePremiumForGroup(group: Item[]): number {
53	  if (isBuildingBlock(group)) {
54	    return BUILDING_BLOCK_BASE_PREMIUM;
55	  }
56	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
57	}
58	
59	function basePremiumForItems(items: Item[]): number {
60	  return groupByKind(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
61	}
62	
63	function quoteStep(step: QuoteStep): QuoteResult {
64	  const basePremium = basePremiumForItems(step.items);
65	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
66	  const premium = Math.ceil(basePremium + surcharge + PROCESSING_FEE);
67	  return { kind: "quote", premium };
68	}
69	
70	export function processScenario(scenario: Scenario): ScenarioResult {
71	  const results = scenario.steps.map(quoteStep);
72	  return { results };
73	}
